(()=>{'use strict';
const T=v=>String(v??'').trim(),$=s=>document.querySelector(s);let draft=null,internalChange=false;
function clean(v){const p=T(v).split(/\s+/).filter(Boolean);if(p.length===2&&p[0]===p[1])return p[0];const o=[];p.forEach(x=>{if(!o.includes(x))o.push(x)});return o.join(' ')}
function sort(a){return[...new Set((a||[]).map(clean).filter(Boolean))].sort((x,y)=>x.localeCompare(y,'th'))}
function selected(){return sort(window.DOIT_SELECTED_PS_LIST||[])}
function allValues(){const rows=Array.isArray(window.__doitAllRows)?window.__doitAllRows:(window.__doitRawRows310||[]);const a=Array.isArray(rows)?rows.map(r=>clean(r.ps)):[];const el=$('#psSelect'),b=el?[...el.options].map(o=>clean(o.value||o.textContent)):[];const c=[...document.querySelectorAll('.psItem289')].map(x=>clean(x.dataset.v||x.textContent));return sort([...a,...b,...c])}
function label(list=selected()){const f=sort(list),b=$('#psTickBtn289'),c=$('#psCount289'),el=$('#psSelect');if(b)b.textContent=f.length?`PS: ${f.length===1?f[0]:f.length+' คน'} ▼`:'PS: ทั้งหมด ▼';if(c)c.textContent=f.length?`เลือกอยู่ ${f.length} คน: ${f.join(', ')}`:'เลือกอยู่: ทั้งหมด';if(el)el.value=f.length===1?f[0]:''}
function triggerProductSelect(reason){const el=$('#psSelect');if(!el)return;if(reason==='legacy-select')return;internalChange=true;try{el.dispatchEvent(new Event('change',{bubbles:true}))}finally{setTimeout(()=>{internalChange=false},0)}}
function publish(list,reason){const f=sort(list);window.DOIT_SELECTED_PS_LIST=f;window.DOIT_SELECTED_PS_KEY=f.join('||');window.DOIT_APP_SCOPE={...(window.DOIT_APP_SCOPE||{}),ps:f,psKey:window.DOIT_SELECTED_PS_KEY};label(f);document.dispatchEvent(new CustomEvent('doit:psChanged',{detail:{ps:f,psKey:window.DOIT_SELECTED_PS_KEY,reason:reason||'ps'}}));triggerProductSelect(reason||'ps');return f}
function paint(){const d=draft||new Set(selected());document.querySelectorAll('.psItem289').forEach(btn=>{const v=clean(btn.dataset.v||btn.textContent),on=d.has(v);btn.classList.toggle('on',on);const i=btn.querySelector('i');if(i)i.textContent=on?'✓':''});label([...d])}
function openSync(){draft=new Set(selected());setTimeout(paint,30);setTimeout(paint,160)}
function toggle(btn){const v=clean(btn.dataset.v||btn.textContent);if(!v)return;draft=draft||new Set(selected());if(draft.has(v))draft.delete(v);else draft.add(v);paint()}
function ok(){publish([...(draft||new Set(selected()))],'ok');draft=null;document.querySelector('.psOverlay289')?.classList.remove('on')}
function clear(){draft=new Set();publish([],'clear');paint();document.querySelector('.psOverlay289')?.classList.remove('on')}
function all(){draft=new Set(allValues());paint()}
function bind(){if(document.__psCleanController310)return;document.__psCleanController310=true;document.addEventListener('click',e=>{const open=e.target?.closest?.('#psTickBtn289'),item=e.target?.closest?.('.psItem289'),okBtn=e.target?.closest?.('.psOk289'),close=e.target?.closest?.('.psClose289'),clearBtn=e.target?.closest?.('.psClear289'),allBtn=e.target?.closest?.('.psAll289');if(open){setTimeout(openSync,40);return}if(item){e.preventDefault();e.stopImmediatePropagation();toggle(item);return}if(okBtn){e.preventDefault();e.stopImmediatePropagation();ok();return}if(clearBtn){e.preventDefault();e.stopImmediatePropagation();clear();return}if(allBtn){e.preventDefault();e.stopImmediatePropagation();all();return}if(close){draft=null;label();return}},true);document.addEventListener('input',e=>{if(e.target?.id==='psSearch289')setTimeout(paint,60)},true);document.addEventListener('change',e=>{if(e.target?.id==='psSelect'){if(internalChange)return;const v=clean(e.target.value);publish(v?[v]:[],'legacy-select')}},true);document.addEventListener('doit:psPopupOpened',openSync)}
function boot(){bind();label();let n=0;const t=()=>{label();if(++n<8)setTimeout(t,600)};setTimeout(t,200)}
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();
})();